INSERT INTO public.soal (kategori, teks_soal, opsi_a, opsi_b, opsi_c, opsi_d, opsi_e, kunci_jawaban)
VALUES
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 1 - Logika Deduktif</h3><p class="text-lg mb-4">Semua atlet profesional menjaga pola makan. Sebagian orang yang menjaga pola makan jarang sakit.</p><p class="text-lg">Simpulan yang tepat adalah...</p></div>$$, $$Semua atlet profesional jarang sakit.$$, $$Sebagian atlet profesional jarang sakit.$$, $$Orang yang jarang sakit adalah atlet profesional.$$, $$Semua orang yang jarang sakit adalah atlet profesional.$$, $$Tidak dapat ditarik kesimpulan.$$, 'E'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 2 - Logika Deduktif</h3><p class="text-lg mb-4">Jika harga kedelai naik, maka harga tahu dan tempe naik. Jika harga tahu dan tempe naik, maka daya beli masyarakat menurun. Diketahui daya beli masyarakat tidak menurun.</p><p class="text-lg">Simpulan yang benar adalah...</p></div>$$, $$Harga tahu dan tempe naik.$$, $$Harga kedelai tidak naik.$$, $$Harga kedelai naik tapi daya beli stabil.$$, $$Masyarakat tidak suka tahu dan tempe.$$, $$Harga kedelai stabil namun langka.$$, 'B'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 3 - Logika Deduktif</h3><p class="text-lg mb-4">Pengurus inti ekstrakurikuler harus hadir rapat. Andi adalah anggota ekstrakurikuler tetapi bukan pengurus inti.</p><p class="text-lg">Simpulan yang benar adalah...</p></div>$$, $$Andi harus hadir rapat.$$, $$Andi tidak boleh hadir rapat.$$, $$Andi mungkin hadir rapat.$$, $$Andi tidak harus hadir rapat.$$, $$Andi adalah ketua ekstrakurikuler.$$, 'D'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 4 - Logika Analitik</h3><p class="text-lg mb-4">Dalam antrean tiket, Budi ada di belakang Ani. Cici ada di depan Ani. Dedi ada di antara Cici dan Ani.</p><p class="text-lg">Urutan antrean dari depan ke belakang adalah...</p></div>$$, $$Cici - Dedi - Ani - Budi$$, $$Cici - Ani - Dedi - Budi$$, $$Dedi - Cici - Ani - Budi$$, $$Ani - Budi - Cici - Dedi$$, $$Budi - Ani - Dedi - Cici$$, 'A'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 5 - Logika Deduktif</h3><p class="text-lg mb-4">Tidak ada pemalas yang sukses. Sebagian orang kaya adalah pemalas.</p><p class="text-lg">Simpulan yang tepat adalah...</p></div>$$, $$Semua orang kaya tidak sukses.$$, $$Sebagian orang kaya tidak sukses.$$, $$Semua pemalas adalah orang kaya.$$, $$Orang yang sukses pasti kaya.$$, $$Sebagian orang sukses adalah pemalas.$$, 'B'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 6 - Logika Deduktif</h3><p class="text-lg mb-4">Jika hujan turun, jalanan licin. Jika jalanan licin, banyak pengendara motor menepi. Saat ini tidak banyak pengendara motor menepi.</p><p class="text-lg">Simpulan yang tepat adalah...</p></div>$$, $$Hujan turun dengan deras.$$, $$Jalanan sangat licin.$$, $$Hujan tidak turun.$$, $$Pengendara motor nekat melaju.$$, $$Tidak ada hubungan antara hujan dan pengendara.$$, 'C'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 7 - Logika Deduktif</h3><p class="text-lg mb-4">Semua peserta SNBT harus memiliki akun SNPMB. Rina tidak memiliki akun SNPMB.</p><p class="text-lg">Maka...</p></div>$$, $$Rina adalah peserta SNBT.$$, $$Rina mungkin peserta SNBT.$$, $$Rina bukan peserta SNBT.$$, $$Rina lupa password akunnya.$$, $$Semua yang punya akun adalah Rina.$$, 'C'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 8 - Logika Deduktif</h3><p class="text-lg mb-4">Jika lampu merah menyala, kendaraan harus berhenti. Mobil Pak Ahmad terus melaju melewati perempatan.</p><p class="text-lg">Simpulan yang paling mungkin adalah...</p></div>$$, $$Pak Ahmad melanggar lalu lintas atau lampu sedang hijau.$$, $$Pak Ahmad pasti ditilang polisi.$$, $$Lampu merah sedang rusak.$$, $$Kendaraan Pak Ahmad remnya blong.$$, $$Pak Ahmad tidak melihat lampu.$$, 'A'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 9 - Logika Analitik</h3><p class="text-lg mb-4">Lima buku (A, B, C, D, E) disusun di rak. Buku A harus di paling kiri. Buku C harus di sebelah kanan buku B. Buku E tidak boleh di ujung.</p><p class="text-lg">Susunan yang mungkin adalah...</p></div>$$, $$A, E, B, C, D$$, $$B, C, A, E, D$$, $$A, B, D, C, E$$, $$D, A, B, C, E$$, $$A, D, E, B, C$$, 'A'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 10 - Logika Deduktif</h3><p class="text-lg mb-4">Semua kertas terbuat dari kayu. Sebagian benda di ruangan ini adalah kertas.</p><p class="text-lg">Simpulan yang tepat adalah...</p></div>$$, $$Semua benda di ruangan ini terbuat dari kayu.$$, $$Sebagian benda di ruangan ini terbuat dari kayu.$$, $$Tidak ada benda di ruangan ini yang terbuat dari kayu.$$, $$Kayu hanya digunakan untuk membuat kertas.$$, $$Semua yang terbuat dari kayu adalah kertas.$$, 'B'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 11 - Analisis Teks</h3><p class="text-lg mb-4">Pemerintah kota menerapkan larangan penggunaan kantong plastik. Data menunjukkan volume sampah plastik di TPA menurun 20% dalam satu bulan.</p><p class="text-lg">Manakah pernyataan yang <strong>memperkuat</strong> argumen bahwa kebijakan tersebut efektif?</p></div>$$, $$Warga kota beralih menggunakan tas belanja kain.$$, $$Produksi plastik di pabrik meningkat.$$, $$Harga kantong plastik menjadi sangat murah.$$, $$Banyak warga membuang sampah ke sungai.$$, $$TPA mengalami kebakaran hebat.$$, 'A'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 12 - Analisis Sebab-Akibat</h3><p class="text-lg mb-4">Kemacetan di Jakarta semakin parah setiap tahun. Penjualan mobil murah meningkat pesat.</p><p class="text-lg">Hubungan yang paling mungkin antara kedua pernyataan tersebut adalah...</p></div>$$, $$Pernyataan pertama adalah penyebab dan pernyataan kedua adalah akibat.$$, $$Pernyataan kedua adalah penyebab dan pernyataan pertama adalah akibat.$$, $$Keduanya adalah akibat dari penyebab yang tidak disebutkan.$$, $$Keduanya tidak saling berhubungan.$$, $$Keduanya adalah penyebab dari masalah lingkungan.$$, 'B'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 13 - Analisis Data</h3><p class="text-lg mb-4">Tabel nilai menunjukkan siswa yang tidur 8 jam memiliki rata-rata nilai 85. Siswa yang tidur kurang dari 5 jam memiliki rata-rata nilai 60.</p><p class="text-lg">Simpulan yang paling didukung oleh data adalah...</p></div>$$, $$Semua siswa pintar pasti tidur 8 jam.$$, $$Durasi tidur berkorelasi positif dengan performa akademik.$$, $$Tidur siang tidak berpengaruh pada nilai.$$, $$Kurang tidur membuat siswa menjadi bodoh.$$, $$Nilai ujian ditentukan oleh keberuntungan.$$, 'B'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 14 - Analisis Teks</h3><p class="text-lg mb-4">Kopi mengandung kafein yang dapat meningkatkan kewaspadaan. Namun, konsumsi berlebihan dapat menyebabkan jantung berdebar dan insomnia.</p><p class="text-lg">Pernyataan yang <strong>memperlemah</strong> bahaya kopi adalah...</p></div>$$, $$Minum kopi membuat orang sulit tidur.$$, $$Banyak orang mengalami asam lambung naik setelah minum kopi.$$, $$Penelitian terbaru menunjukkan kopi dalam takaran wajar mencegah Alzheimer.$$, $$Kafein adalah zat adiktif.$$, $$Harga kopi semakin mahal.$$, 'C'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 15 - Analisis Teks</h3><p class="text-lg mb-4">Bunga mawar di taman layu saat musim kemarau. Rumput di lapangan juga menguning saat musim kemarau.</p><p class="text-lg">Generalisasi yang paling mungkin adalah...</p></div>$$, $$Semua tanaman mati saat musim kemarau.$$, $$Hanya mawar dan rumput yang butuh air.$$, $$Kekurangan air pada musim kemarau berdampak buruk pada tanaman.$$, $$Musim hujan adalah musim terbaik untuk bertani.$$, $$Tukang kebun sedang libur.$$, 'C'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 16 - Analisis Data</h3><p class="text-lg mb-4">Grafik pengunjung perpustakaan menurun drastis sejak internet gratis tersedia di taman kota.</p><p class="text-lg">Hipotesis yang paling mungkin menjelaskan fenomena ini adalah...</p></div>$$, $$Orang lebih suka membaca buku di taman.$$, $$Perpustakaan sedang direnovasi.$$, $$Akses informasi digital menggantikan kebutuhan fisik ke perpustakaan.$$, $$Harga buku menjadi sangat mahal.$$, $$Taman kota memiliki koleksi buku yang lengkap.$$, 'C'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 17 - Analisis Teks</h3><p class="text-lg mb-4">PT Kereta Api meluncurkan kereta mewah dengan fasilitas tidur. Tiket kereta tersebut terjual habis dalam 1 jam.</p><p class="text-lg">Simpulan tentang perilaku konsumen adalah...</p></div>$$, $$Konsumen tidak peduli harga demi kenyamanan.$$, $$Masyarakat lebih suka naik pesawat.$$, $$Kereta api adalah transportasi termurah.$$, $$Tiket kereta api terlalu sedikit.$$, $$Sistem penjualan tiket mengalami error.$$, 'A'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 18 - Analisis Sebab-Akibat</h3><p class="text-lg mb-4">Terjadi peningkatan kasus demam berdarah di Desa Sukamaju. Banyak genangan air ditemukan di pekarangan warga.</p><p class="text-lg">Solusi paling logis untuk memutus rantai sebab-akibat ini adalah...</p></div>$$, $$Membagikan obat demam gratis.$$, $$Melakukan fogging dan menguras genangan air (3M).$$, $$Membangun rumah sakit baru.$$, $$Melarang warga keluar rumah.$$, $$Menebang semua pohon di desa.$$, 'B'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 19 - Analisis Teks</h3><p class="text-lg mb-4">Susu sapi mengandung kalsium tinggi. Ikan teri juga mengandung kalsium tinggi.</p><p class="text-lg">Simpulan induktif yang tepat adalah...</p></div>$$, $$Hanya susu dan ikan teri yang mengandung kalsium.$$, $$Berbagai jenis makanan hewani dapat menjadi sumber kalsium.$$, $$Semua makanan laut mengandung kalsium.$$, $$Susu sapi lebih baik daripada ikan teri.$$, $$Kalsium hanya terdapat pada benda cair.$$, 'B'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 20 - Analisis Data</h3><p class="text-lg mb-4">Penjualan jaket tebal meningkat di bulan Desember. Penjualan es krim menurun di bulan Desember.</p><p class="text-lg">Kondisi yang paling mungkin terjadi di bulan Desember adalah...</p></div>$$, $$Terjadi krisis ekonomi.$$, $$Sedang berlangsung musim panas.$$, $$Sedang berlangsung musim dingin/hujan.$$, $$Masyarakat sedang diet.$$, $$Ada diskon besar-besaran untuk jaket.$$, 'C'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 21 - Pola Bilangan</h3><p class="text-lg mb-4">2, 4, 8, 14, 22, ...</p><p class="text-lg">Angka selanjutnya dalam barisan tersebut adalah...</p></div>$$, $$30$$, $$32$$, $$34$$, $$36$$, $$40$$, 'B'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 22 - Pola Huruf</h3><p class="text-lg mb-4">A, C, F, J, O, ...</p><p class="text-lg">Huruf selanjutnya adalah...</p></div>$$, $$T$$, $$U$$, $$V$$, $$S$$, $$R$$, 'B'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 23 - Operasi Bilangan</h3><p class="text-lg mb-4">Jika a = 5 dan b = 2, maka nilai dari $a^2 + 2ab + b^2$ adalah...</p></div>$$, $$29$$, $$49$$, $$39$$, $$25$$, $$14$$, 'B'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 24 - Logika Aritmatika</h3><p class="text-lg mb-4">Sebuah baju berharga Rp100.000 diskon 50% + 20%. Berapa harga akhir baju tersebut?</p></div>$$, $$Rp30.000$$, $$Rp40.000$$, $$Rp50.000$$, $$Rp70.000$$, $$Rp80.000$$, 'B'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 25 - Pola Bilangan</h3><p class="text-lg mb-4">100, 95, 85, 70, 50, ...</p><p class="text-lg">Angka selanjutnya adalah...</p></div>$$, $$20$$, $$25$$, $$30$$, $$35$$, $$15$$, 'B'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 26 - Hubungan x dan y</h3><p class="text-lg mb-4">Jika $x = 1/3$ dan $y = 33%$, manakah pernyataan yang benar?</p></div>$$, $$x > y$$, $$x < y$$, $$x = y$$, $$x = 2y$$, $$Hubungan tidak dapat ditentukan$$, 'A'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 27 - Aritmatika Sosial</h3><p class="text-lg mb-4">Budi membeli 3 buku seharga Rp15.000. Jika ia ingin membeli 10 buku, berapa yang harus dibayar?</p></div>$$, $$Rp45.000$$, $$Rp50.000$$, $$Rp60.000$$, $$Rp40.000$$, $$Rp55.000$$, 'B'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 28 - Geometri Dasar</h3><p class="text-lg mb-4">Jika luas persegi adalah 64 cm², maka keliling persegi tersebut adalah...</p></div>$$, $$16 cm$$, $$24 cm$$, $$32 cm$$, $$36 cm$$, $$64 cm$$, 'C'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 29 - Operasi Simbol</h3><p class="text-lg mb-4">Jika A # B artinya (A x B) - A, maka nilai dari 4 # 5 adalah...</p></div>$$, $$16$$, $$20$$, $$15$$, $$19$$, $$24$$, 'A'),
  ($$PU$$, $$<div class="py-4 text-slate-800"><h3 class="font-bold text-slate-400 mb-4 uppercase text-xs">No. 30 - Pecahan</h3><p class="text-lg mb-4">Manakah pecahan yang nilainya paling besar?</p></div>$$, $$1/2$$, $$2/3$$, $$3/5$$, $$4/7$$, $$5/9$$, 'B'),
  ($$PBM$$, $$<div class="split-layout text-slate-800"><div class="reading-pane prose prose-slate"><h3>Teks 1: Gajah di Thailand</h3><p>(1) Pang Premchuenpanawan dan beberapa pawang mendorong gajah pulang dengan berjalan kaki, hingga ratusan kilometer menuju ke kampung halaman mereka di Provinsi Chiang Mai untuk bertahan hidup di tengah pandemi Covid-19. (2) Di dalam rombongan tersebut terdapat satu ekor bayi gajah berusia empat bulan dan gajah yang berusia enam puluh tahun. (3) Perjalanan pulang tersebut panjang dan sulit, bahkan rombongan mereka pernah diusir keluar dari sebuah desa, karena dianggap terbawa virus corona. (4) Ada sekitar 3000 gajah yang bekerja diindustri pariwisata di Thailand. (5) Pandemi Covid-19 membuat industri pariwisata hancur dan beberapa gajah-gajah kehilangan pekerjaan, dengan suplai makanan yang minim.</p></div><div class="question-pane"><p class="font-bold">Pertanyaan 1:</p><p>Penulisan kata yang tidak tepat pada teks di atas terdapat pada kalimat nomor...</p></div></div>$$, $$(1)$$, $$(2)$$, $$(3)$$, $$(4)$$, $$(5)$$, 'D'),
  ($$PBM$$, $$<div class="split-layout text-slate-800"><div class="reading-pane prose prose-slate"><h3>Teks 1: Gajah di Thailand</h3><p>(1) Pang Premchuenpanawan dan beberapa pawang mendorong gajah pulang dengan berjalan kaki, hingga ratusan kilometer menuju ke kampung halaman mereka di Provinsi Chiang Mai untuk bertahan hidup di tengah pandemi Covid-19. (2) Di dalam rombongan tersebut terdapat satu ekor bayi gajah berusia empat bulan dan gajah yang berusia enam puluh tahun. (3) Perjalanan pulang tersebut panjang dan sulit, bahkan rombongan mereka pernah diusir keluar dari sebuah desa, karena dianggap terbawa virus corona. (4) Ada sekitar 3000 gajah yang bekerja diindustri pariwisata di Thailand. (5) Pandemi Covid-19 membuat industri pariwisata hancur dan beberapa gajah-gajah kehilangan pekerjaan, dengan suplai makanan yang minim.</p></div><div class="question-pane"><p class="font-bold">Pertanyaan 2:</p><p>Kesalahan penggunaan kata pada kalimat (3) terdapat pada kata...</p></div></div>$$, $$panjang$$, $$sulit$$, $$terbawa$$, $$dianggap$$, $$rombongan$$, 'C'),
